import { notFound } from 'next/navigation';
import CooperativeList from '../../../components/CooperativeList';
import ExploreMap from '../../../components/Map';
import ProductCard from '../../../components/ProductCard';
import { cooperatives } from '../../../data/mockData';

type ZonePageProps = {
  params: Promise<{ slug: string }>;
};

function slugifyZone(zone: string) {
  return zone
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '-');
}

export function generateStaticParams() {
  const zones = Array.from(new Set(cooperatives.map((cooperative) => cooperative.zone)));
  return zones.map((zone) => ({ slug: slugifyZone(zone) }));
}

export default async function ZonePage({ params }: ZonePageProps) {
  const { slug } = await params;
  const zone = Array.from(new Set(cooperatives.map((cooperative) => cooperative.zone))).find(
    (item) => slugifyZone(item) === slug,
  );

  if (!zone) {
    notFound();
  }

  const zoneCooperatives = cooperatives.filter((cooperative) => cooperative.zone === zone);
  const zoneProducts = zoneCooperatives.flatMap((cooperative) =>
    cooperative.products.map((product) => ({ ...product, cooperativeSlug: cooperative.slug })),
  );

  return (
    <section className="space-y-4">
      <div className="rounded-2xl border border-white/40 bg-white/75 p-5 shadow-soft backdrop-blur-md">
        <p className="text-xs uppercase tracking-wide text-terracotta">Hub Regional</p>
        <h1 className="mt-1 text-2xl font-semibold text-palmier">Zone {zone}</h1>
        <p className="mt-2 text-sm text-palmier/80">
          Carte et catalogue dedies a la zone {zone}. Decouvrez les cooperativés locales et leurs
          produits specifiques.
        </p>
      </div>

      <div className="grid grid-cols-1 gap-4 lg:grid-cols-[55%_45%]">
        <ExploreMap cooperatives={zoneCooperatives} className="h-[58vh] lg:h-[70vh]" />
        <CooperativeList cooperatives={zoneCooperatives} />
      </div>

      <div className="rounded-2xl border border-white/40 bg-white/75 p-5 shadow-soft backdrop-blur-md">
        <h2 className="text-xl font-semibold text-palmier">Produits de la zone {zone}</h2>
        <div className="mt-4 grid grid-cols-1 gap-4 sm:grid-cols-2 xl:grid-cols-3">
          {zoneProducts.map((product, index) => (
            <ProductCard
              key={product.id}
              product={product}
              cooperativeSlug={product.cooperativeSlug}
              index={index}
            />
          ))}
        </div>
      </div>
    </section>
  );
}
